CREATE POLICY "Admins update broadcasts" ON public.broadcasts FOR UPDATE USING (EXISTS (SELECT 1 FROM profiles WHERE profiles.id = (SELECT auth.uid()) AND profiles.role = ANY (ARRAY['admin', 'super_admin']))); CREATE POLICY "Admins update suspensions" ON public.class_suspensions FOR UPDATE USING (EXISTS (SELECT 1 FROM profiles WHERE profiles.id = (SELECT auth.uid()) AND profiles.role = ANY (ARRAY['admin', 'super_admin'])));;
